use std::fs;
use std::io::{BufRead, BufReader};
use std::path::Path;

/// Deferred security items: per-token auth, TLS termination, CORS multi-tenant
/// policies, and API key rotation are not yet implemented. These are tracked as
/// M7+ backlog. Current surface is loopback-only (127.0.0.1) which limits
/// exposure without additional network controls.
pub struct SecurityTechDebt;

pub fn validate_embedding_debt_jsonl(path: &Path) -> Result<usize, String> {
    let file = fs::File::open(path)
        .map_err(|e| format!("cannot open embedding_debt.jsonl: {e}"))?;
    let reader = BufReader::new(file);
    let mut valid_count = 0usize;
    for (line_num, line_result) in reader.lines().enumerate() {
        let line = line_result
            .map_err(|e| format!("read error at line {line_num}: {e}"))?;
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        serde_json::from_str::<serde_json::Value>(trimmed)
            .map_err(|e| format!("invalid JSON at line {line_num}: {e}"))?;
        valid_count += 1;
    }
    Ok(valid_count)
}

pub fn validate_snapshot_bin_header(path: &Path) -> Result<(), String> {
    let bytes = fs::read(path)
        .map_err(|e| format!("cannot read snapshot file: {e}"))?;
    let magic = crate::snapshot::MAGIC;
    if bytes.len() < magic.len() {
        return Err("snapshot file too small to contain magic header".to_string());
    }
    if &bytes[..magic.len()] != magic.as_ref() {
        return Err("snapshot magic header mismatch — file may be corrupt or invalid".to_string());
    }
    Ok(())
}

use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};
use std::time::Duration;

use crate::circuit_breaker::CircuitBreaker;

use crate::git::RepoIdentity;
use crate::indexer::pipeline::IndexingPipeline;
use crate::repo_watcher::RepoWatcher;
use crate::search::retriever::SearchBackend;
use crate::state::{PrevalentState, RepoIndex};

pub const VAULT_DIR_NAME: &str = "prometheus";

fn collect_md_entry(path: PathBuf, out: &mut Vec<PathBuf>) {
    // Ignore junk directories early for performance and to avoid indexing vendor files
    if path.is_dir() {
        if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
            if name.starts_with('.')
                || name == "node_modules"
                || name == "target"
                || name == "vendor"
                || name == "venv"
                || name == ".venv"
                || name == VAULT_DIR_NAME
            {
                return;
            }
        }
        walk_md_files(&path, out);
        return;
    }
    if path.extension().is_some_and(|ext| ext == "md") {
        out.push(path);
    }
}

pub fn walk_md_files(dir: &Path, out: &mut Vec<PathBuf>) {
    let Ok(entries) = std::fs::read_dir(dir) else { return };
    for entry in entries.filter_map(|e| e.ok()) {
        collect_md_entry(entry.path(), out);
    }
}

pub async fn ingest_file_chunks(
    repo_id: &str,
    file_path: &Path,
    pipeline: &mut IndexingPipeline,
    state: &Arc<Mutex<PrevalentState>>,
) {
    use crate::embedding_provider::{EmbeddingProvider, EmbeddingProviderKind, OllamaProvider};
    let Ok(content) = std::fs::read_to_string(file_path) else { return };
    let file_str = file_path.to_string_lossy().into_owned();
    let tagged_chunks = pipeline.process_file_with_dirty_markers(repo_id, &file_str, &content);
    let provider_kind = EmbeddingProviderKind::from_env();
    let embedder = provider_kind.is_ollama().then(OllamaProvider::from_env);
    let mut results = Vec::new();
    for (chunk, is_dirty) in tagged_chunks {
        let vec = if is_dirty {
            if let Some(ref e) = embedder { e.embed_text(&chunk.text).await.ok() } else { None }
        } else {
            None
        };
        results.push((chunk, vec));
    }
    let mut guard = state.lock().unwrap();
    for (chunk, vector) in results {
        if let Some(v) = vector {
            let _ = guard.search_index.add_chunk_with_vector(&chunk, v);
        } else {
            let _ = guard.search_index.add_chunk(&chunk);
        }
    }
}

pub async fn index_repo(
    repo_path: &Path,
    pipeline: &mut IndexingPipeline,
    state: &Arc<Mutex<PrevalentState>>,
) {
    let repo_id = RepoIdentity::from_path(repo_path)
        .map(|id| id.repo_id)
        .unwrap_or_else(|_| {
            repo_path
                .file_name()
                .map(|n| n.to_string_lossy().into_owned())
                .unwrap_or_default()
        });
    let mut markdown_file_paths = Vec::new();
    walk_md_files(repo_path, &mut markdown_file_paths);
    for file_path in &markdown_file_paths {
        ingest_file_chunks(&repo_id, file_path, pipeline, state).await;
    }
    let mut guard = state.lock().unwrap();
    guard.repos.insert(
        repo_id.clone(),
        RepoIndex { repo_id, chunk_count: markdown_file_paths.len() },
    );
}

pub async fn index_vault_worktree(
    repo_path: &Path,
    pipeline: &mut IndexingPipeline,
    state: &Arc<Mutex<PrevalentState>>,
) {
    let vault = repo_path.join(VAULT_DIR_NAME);
    if !vault.join(".git").is_file() {
        return;
    }
    let repo_id = format!(
        "{}-vault",
        repo_path.file_name().map(|n| n.to_string_lossy()).unwrap_or_default()
    );
    let mut paths = Vec::new();
    walk_md_files(&vault, &mut paths);
    for file_path in &paths {
        ingest_file_chunks(&repo_id, file_path, pipeline, state).await;
    }
    let count = paths.len();
    let mut guard = state.lock().unwrap();
    guard.repos.insert(
        repo_id.clone(),
        RepoIndex { repo_id, chunk_count: count },
    );
}

pub async fn index_vaults_on_boot(state: Arc<Mutex<PrevalentState>>) {
    let vaults_dir = RepoWatcher::vaults_dir_from_env();
    let (tx, _rx) = std::sync::mpsc::channel();
    let watcher = RepoWatcher::new(vaults_dir, tx);
    let repos = watcher.scan_existing_repos();
    let mut pipeline = IndexingPipeline::new_from_env();
    let mut circuit_breaker = CircuitBreaker::default();
    for repo_path in &repos {
        if !circuit_breaker.is_available(repo_path) {
            tracing::info!(repo = %repo_path.display(), "repo offline (circuit breaker) — skipping");
            continue;
        }
        let result = tokio::time::timeout(
            Duration::from_millis(500),
            async {
                index_repo(repo_path, &mut pipeline, &state).await;
                index_vault_worktree(repo_path, &mut pipeline, &state).await;
            },
        )
        .await;
        if result.is_err() {
            tracing::warn!(repo = %repo_path.display(), "repo offline — skipping (I/O timeout)");
            circuit_breaker.mark_offline(repo_path);
        }
    }
    let mut guard = state.lock().unwrap();
    let _ = guard.search_index.commit();
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;

    #[test]
    fn walker_excludes_prometheus_directory() {
        let tmp = tempfile::tempdir().expect("tempdir");
        let prometheus_dir = tmp.path().join("prometheus");
        fs::create_dir_all(&prometheus_dir).unwrap();
        fs::write(prometheus_dir.join("secret.md"), "# secret").unwrap();

        let mut results = Vec::new();
        walk_md_files(tmp.path(), &mut results);

        assert!(
            results.iter().all(|p| !p.starts_with(&prometheus_dir)),
            "prometheus/ files must not appear in walker results"
        );
    }

    #[test]
    fn circuit_breaker_mark_then_skip() {
        let mut cb = CircuitBreaker::new(std::time::Duration::from_secs(60));
        let repo = std::path::PathBuf::from("/tmp/boot_test_repo");
        assert!(cb.is_available(&repo), "initially available");
        cb.mark_offline(&repo);
        assert!(!cb.is_available(&repo), "unavailable after mark_offline");
    }

    #[test]
    fn walker_includes_normal_directories() {
        let tmp = tempfile::tempdir().expect("tempdir");
        let docs_dir = tmp.path().join("docs");
        fs::create_dir_all(&docs_dir).unwrap();
        let md_file = docs_dir.join("guide.md");
        fs::write(&md_file, "# Guide").unwrap();

        let mut results = Vec::new();
        walk_md_files(tmp.path(), &mut results);

        assert!(
            results.contains(&md_file),
            "docs/guide.md must appear in walker results"
        );
    }
}

use std::collections::HashMap;
use std::path::Path;
use std::time::{Duration, Instant};

const DEFAULT_COOLDOWN_SECS: u64 = 300; // 5 minutes
const COOLDOWN_ENV_VAR: &str = "PKS_CIRCUIT_BREAKER_COOLDOWN_SECS";

pub struct CircuitBreaker {
    offline_repos: HashMap<String, Instant>,
    cooldown: Duration,
}

impl CircuitBreaker {
    pub fn new(cooldown: Duration) -> Self {
        Self {
            offline_repos: HashMap::new(),
            cooldown,
        }
    }

    pub fn default_cooldown() -> Duration {
        let secs = std::env::var(COOLDOWN_ENV_VAR)
            .ok()
            .and_then(|v| v.parse::<u64>().ok())
            .unwrap_or(DEFAULT_COOLDOWN_SECS);
        Duration::from_secs(secs)
    }

    pub fn mark_offline(&mut self, repo_path: &Path) {
        let key = repo_path.to_string_lossy().into_owned();
        self.offline_repos.insert(key, Instant::now());
    }

    pub fn is_available(&self, repo_path: &Path) -> bool {
        let key = repo_path.to_string_lossy();
        match self.offline_repos.get(key.as_ref()) {
            None => true,
            Some(since) => since.elapsed() >= self.cooldown,
        }
    }
}

impl Default for CircuitBreaker {
    fn default() -> Self {
        Self::new(Self::default_cooldown())
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::path::PathBuf;

    #[test]
    fn mark_offline_then_is_available_returns_false() {
        let mut cb = CircuitBreaker::new(Duration::from_secs(60));
        let repo = PathBuf::from("/tmp/test_repo");
        cb.mark_offline(&repo);
        assert!(!cb.is_available(&repo));
    }

    #[test]
    fn after_cooldown_expires_is_available_returns_true() {
        let mut cb = CircuitBreaker::new(Duration::from_millis(10));
        let repo = PathBuf::from("/tmp/test_repo_cooldown");
        cb.mark_offline(&repo);
        std::thread::sleep(Duration::from_millis(20));
        assert!(cb.is_available(&repo));
    }

    #[test]
    fn unknown_repo_is_always_available() {
        let cb = CircuitBreaker::new(Duration::from_secs(60));
        let repo = PathBuf::from("/tmp/unknown_repo");
        assert!(cb.is_available(&repo));
    }
}

use chrono::Utc;

use crate::knowledge_writer::{
    build_decision_content, commit_to_vault, decision_file_path,
    hash_8, safe_truncate, try_ipc_refresh,
};

/// Implements `pks decision "<note>"`.
/// Writes an ADR to `decisions/` on the pks-knowledge branch.
pub fn run_decision(note: &str) -> i32 {
    if note.trim().is_empty() {
        eprintln!("pks decision: note cannot be empty. Usage: pks decision \"<note>\"");
        return 1;
    }
    let cwd = match std::env::current_dir() {
        Ok(p) => p,
        Err(e) => { eprintln!("pks decision: cannot determine cwd: {e}"); return 1; }
    };
    let now = Utc::now();
    let date_str = now.format("%Y-%m-%d").to_string();
    let hash = hash_8(note);
    let content = build_decision_content(note, &now.to_rfc3339(), "cli", None);
    let file_path = decision_file_path(&date_str, &hash);
    let message = format!("pks(decision): {}", safe_truncate(note, 60));

    if let Err(e) = commit_to_vault(&cwd, &file_path, content.as_bytes(), &message) {
        eprintln!("pks decision: {e}");
        return 1;
    }
    println!("✓ Decision recorded: {file_path}");
    try_ipc_refresh();
    0
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::git::BareCommit;
    use crate::knowledge_writer::{build_decision_content, decision_file_path, hash_8};
    use git2::Repository;
    use tempfile::TempDir;

    fn init_repo() -> TempDir {
        let tmp = tempfile::tempdir().unwrap();
        let repo = Repository::init(tmp.path()).unwrap();
        let mut cfg = repo.config().unwrap();
        cfg.set_str("user.name", "pks-test").unwrap();
        cfg.set_str("user.email", "pks@test.local").unwrap();
        tmp
    }

    #[test]
    fn build_content_has_frontmatter() {
        let c = build_decision_content("Test", "2026-03-20T10:00:00Z", "cli", None);
        assert!(c.starts_with("---\n"));
        assert!(c.contains("source: cli"));
        assert!(c.contains("# Test"));
    }

    #[test]
    fn decision_file_path_format() {
        let p = decision_file_path("2026-03-20", "abcd1234");
        assert_eq!(p, "decisions/2026-03-20_abcd1234.md");
    }

    #[test]
    fn full_flow_writes_to_pks_knowledge() {
        let tmp = init_repo();
        let bc = BareCommit::new(tmp.path());
        bc.ensure_branch().unwrap();

        let now = Utc::now();
        let date_str = now.format("%Y-%m-%d").to_string();
        let hash = hash_8("Usar Rust 2024");
        let content = build_decision_content("Usar Rust 2024", &now.to_rfc3339(), "cli", None);
        let file_path = decision_file_path(&date_str, &hash);

        bc.write_file(&file_path, content.as_bytes(), "test decision").unwrap();

        let repo = Repository::open(tmp.path()).unwrap();
        let branch = repo.find_branch("pks-knowledge", git2::BranchType::Local).unwrap();
        let tree = branch.get().peel_to_commit().unwrap().tree().unwrap();
        let decisions_tree = repo.find_tree(tree.get_name("decisions").unwrap().id()).unwrap();
        let expected_name = format!("{date_str}_{hash}.md");
        let entry = decisions_tree.get_name(&expected_name);
        assert!(entry.is_some(), "decision file must exist in pks-knowledge");
        let blob = repo.find_blob(entry.unwrap().id()).unwrap();
        let text = std::str::from_utf8(blob.content()).unwrap();
        assert!(text.contains("source: cli"));
        assert!(text.contains("# Usar Rust 2024"));
    }
}

use std::path::{Path, PathBuf};

use chrono::Utc;

use crate::git::BareCommit;
use crate::hooks::journal_entry::JournalEntry;
use crate::hooks::shadow_journal::ShadowJournalHook;
use crate::ipc::{IpcClient, PksCommand};

fn try_ipc_refresh() {
    let rt = tokio::runtime::Builder::new_current_thread()
        .enable_all()
        .build();
    if let Ok(rt) = rt {
        let _ = rt.block_on(IpcClient::send_command(&PksCommand::Refresh { dry_run: false }));
    }
}

fn parse_entries(content: &str) -> Vec<JournalEntry> {
    content
        .lines()
        .filter(|l| !l.trim().is_empty())
        .filter_map(|line| match serde_json::from_str::<JournalEntry>(line) {
            Ok(e) => Some(e),
            Err(e) => {
                eprintln!("pks flush-session: skipping invalid JSONL line: {e}");
                None
            }
        })
        .collect()
}

fn min_words_threshold() -> usize {
    std::env::var("PKS_JOURNAL_MIN_WORDS")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(10)
}

fn count_words(entries: &[JournalEntry]) -> usize {
    entries
        .iter()
        .flat_map(|e| e.tool_input_summary.split_whitespace())
        .count()
}

fn load_entries(jsonl_path: &Path) -> Option<Vec<JournalEntry>> {
    let content = match std::fs::read_to_string(jsonl_path) {
        Ok(c) => c,
        Err(e) => { eprintln!("pks flush-session: failed to read {}: {e}", jsonl_path.display()); return None; }
    };
    let entries = parse_entries(&content);
    if entries.is_empty() || count_words(&entries) < min_words_threshold() {
        let _ = std::fs::remove_file(jsonl_path);
        return None;
    }
    Some(entries)
}

fn flush_entries(session_id: &str, cwd: &Path, entries: Vec<JournalEntry>) {
    let first_ts = entries.first().map(|e| e.timestamp).unwrap_or_else(Utc::now);
    let hook = ShadowJournalHook::from_entries(cwd.to_path_buf(), session_id.to_string(), first_ts, entries);
    let bc = BareCommit::new(cwd);
    if let Err(e) = hook.flush_to_vault(&bc) {
        eprintln!("pks flush-session: flush_to_vault failed: {e}");
    }
}

/// Core logic for flush-session — accepts an explicit sessions_dir for testability.
pub fn flush_session_with_dir(session_id: &str, cwd: &Path, sessions_dir: &Path) -> i32 {
    let jsonl_path = sessions_dir.join(format!("{session_id}.jsonl"));
    if !jsonl_path.exists() { return 0; }
    let Some(entries) = load_entries(&jsonl_path) else { return 0 };
    flush_entries(session_id, cwd, entries);
    let _ = std::fs::remove_file(&jsonl_path);
    if let Err(e) = crate::hooks::commit_event_log::flush_pending_commits(cwd) {
        eprintln!("pks flush-session: flush pending commits failed: {e}");
    }
    try_ipc_refresh();
    0
}

/// Entry point for `pks flush-session <session_id> <cwd>`.
/// Always returns 0.
pub fn run_flush_session(session_id: &str, cwd: &Path) -> i32 {
    let home = std::env::var("HOME").unwrap_or_else(|_| "/tmp".to_string());
    let sessions_dir = PathBuf::from(home).join(".pks/sessions");
    flush_session_with_dir(session_id, cwd, &sessions_dir)
}

#[cfg(test)]
#[path = "flush_session_tests.rs"]
mod tests;

use super::*;
use chrono::Utc;
use git2::Repository;
use std::path::Path;
use tempfile::TempDir;

fn make_entry(summary: &str) -> JournalEntry {
    JournalEntry {
        timestamp: Utc::now(),
        tool_name: "Edit".to_string(),
        tool_input_summary: summary.to_string(),
        outcome: "success".to_string(),
        file_paths: vec!["src/main.rs".to_string()],
        decision_note: None,
    }
}

fn write_jsonl(dir: &Path, session_id: &str, entries: &[JournalEntry]) {
    std::fs::create_dir_all(dir).unwrap();
    let path = dir.join(format!("{session_id}.jsonl"));
    let lines: Vec<String> = entries
        .iter()
        .map(|e| serde_json::to_string(e).unwrap())
        .collect();
    std::fs::write(path, lines.join("\n")).unwrap();
}

fn init_repo() -> TempDir {
    let tmp = tempfile::tempdir().unwrap();
    let repo = Repository::init(tmp.path()).unwrap();
    let mut cfg = repo.config().unwrap();
    cfg.set_str("user.name", "pks-test").unwrap();
    cfg.set_str("user.email", "pks@test.local").unwrap();
    tmp
}

#[test]
fn nonexistent_jsonl_returns_0() {
    let sessions_dir = tempfile::tempdir().unwrap();
    let cwd = tempfile::tempdir().unwrap();
    let result = flush_session_with_dir("missing-session", cwd.path(), sessions_dir.path());
    assert_eq!(result, 0);
}

#[test]
fn min_words_guard_deletes_file_without_commit() {
    let sessions_dir = tempfile::tempdir().unwrap();
    let repo_dir = init_repo();

    // Only 2 words — below default threshold of 10
    let entries = vec![make_entry("two words")];
    write_jsonl(sessions_dir.path(), "session-001", &entries);

    let jsonl_path = sessions_dir.path().join("session-001.jsonl");
    assert!(jsonl_path.exists());

    let result = flush_session_with_dir("session-001", repo_dir.path(), sessions_dir.path());
    assert_eq!(result, 0);
    assert!(!jsonl_path.exists(), "JSONL must be deleted after min_words guard");

    // No commit should have been made
    let repo = Repository::open(repo_dir.path()).unwrap();
    assert!(
        repo.find_branch("pks-knowledge", git2::BranchType::Local).is_err(),
        "pks-knowledge must not exist when min_words guard fires"
    );
}

fn find_journal_content(repo_path: &Path, session_id: &str) -> Option<String> {
    let repo = Repository::open(repo_path).unwrap();
    let branch = repo.find_branch("pks-knowledge", git2::BranchType::Local).ok()?;
    let tree = branch.get().peel_to_commit().unwrap().tree().unwrap();
    let jt = repo.find_tree(tree.get_name("journals")?.id()).unwrap();
    for i in 0..jt.len() {
        let entry = jt.get(i).unwrap();
        if entry.name().unwrap_or("").contains(session_id) {
            let blob = repo.find_blob(entry.id()).unwrap();
            return Some(std::str::from_utf8(blob.content()).unwrap().to_string());
        }
    }
    None
}

#[test]
fn full_flow_commits_journal_and_deletes_jsonl() {
    let sessions_dir = tempfile::tempdir().unwrap();
    let repo_dir = init_repo();
    let entries = vec![
        make_entry("refactored the authentication module to use JWT tokens and updated tests"),
        make_entry("added integration tests for the login flow endpoint"),
    ];
    write_jsonl(sessions_dir.path(), "session-abc", &entries);
    let jsonl_path = sessions_dir.path().join("session-abc.jsonl");

    let result = flush_session_with_dir("session-abc", repo_dir.path(), sessions_dir.path());
    assert_eq!(result, 0);
    assert!(!jsonl_path.exists(), "JSONL must be deleted after successful flush");

    let content = find_journal_content(repo_dir.path(), "session-abc")
        .expect("journal file for session-abc must exist");
    assert!(content.contains("session-abc"));
    assert!(content.contains("refactored"));
}

use std::path::{Path, PathBuf};
use std::process::Command;

use crate::git::BareCommit;

/// Error type for `pks init`.
#[derive(Debug)]
pub enum InitError {
    NotAGitRepo,
    Io(std::io::Error),
    AlreadyInitialized,
    Git(git2::Error),
}

impl std::fmt::Display for InitError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            InitError::NotAGitRepo => write!(f, "diretório atual não é um repositório Git. Execute `git init` antes de usar `pks init`."),
            InitError::Io(e) => write!(f, "erro de I/O: {e}"),
            InitError::AlreadyInitialized => write!(f, "PKS já inicializado aqui. Use --force para sobrescrever."),
            InitError::Git(e) => write!(f, "erro Git: {e}"),
        }
    }
}

impl From<std::io::Error> for InitError {
    fn from(e: std::io::Error) -> Self { InitError::Io(e) }
}

impl From<git2::Error> for InitError {
    fn from(e: git2::Error) -> Self { InitError::Git(e) }
}

pub struct InitCommand {
    pub project_path: PathBuf,
    pub force: bool,
}

impl InitCommand {
    pub fn new(project_path: PathBuf, force: bool) -> Self {
        Self { project_path, force }
    }

    /// Runs all onboarding steps — completes in < 30s for repos up to 500 .md files.
    pub fn run(&self) -> Result<(), InitError> {
        let git_root = detect_git_root(&self.project_path)?;
        println!("✓ Git root detectado: {}", git_root.display());

        let config_path = git_root.join(".pks").join("config.toml");
        if config_path.exists() && !self.force {
            return Err(InitError::AlreadyInitialized);
        }
        let git_common_dir = detect_git_common_dir(&git_root)?;
        let project_name = git_root
            .file_name()
            .map(|n| n.to_string_lossy().into_owned())
            .unwrap_or_else(|| "unknown".to_string());
        generate_config(&config_path, &project_name, &git_common_dir)?;
        println!("✓ Config gerada: {}", config_path.display());

        let bc = BareCommit::new(&git_root);
        bc.ensure_branch()?;
        println!("✓ Branch criada: pks-knowledge");

        let repo_id = git_common_dir.to_string_lossy().into_owned();
        register_with_daemon(&repo_id);
        println!("✓ Daemon registrado: {project_name} (RepoId: {repo_id})");

        if let Err(e) = add_pks_to_exclude(&git_root) {
            eprintln!("⚠ Aviso: could not update .git/info/exclude: {e}");
        }
        if let Err(e) = hide_worktree_from_vscode(&git_root) {
            eprintln!("⚠ Aviso: could not update .vscode/settings.json: {e}");
        }
        println!("PKS ativo. Buscar: pks search \"<sua consulta>\"");
        Ok(())
    }
}

/// Returns true if `.pks/config.toml` exists at the given path.
pub fn is_initialized(path: &Path) -> bool {
    path.join(".pks").join("config.toml").exists()
}

pub(crate) fn detect_git_root(start: &Path) -> Result<PathBuf, InitError> {
    let output = Command::new("git")
        .args(["-C", start.to_str().unwrap_or("."), "rev-parse", "--show-toplevel"])
        .output()
        .map_err(InitError::Io)?;
    if !output.status.success() {
        return Err(InitError::NotAGitRepo);
    }
    Ok(PathBuf::from(String::from_utf8_lossy(&output.stdout).trim()))
}

fn detect_git_common_dir(git_root: &Path) -> Result<PathBuf, InitError> {
    use crate::git::RepoIdentity;
    RepoIdentity::from_path(git_root)
        .map(|id| id.git_common_dir)
        .map_err(InitError::Git)
}

pub(crate) fn generate_config(config_path: &Path, name: &str, git_common_dir: &Path) -> Result<(), InitError> {
    use std::fs::{self, OpenOptions};
    use std::io::Write;
    if let Some(parent) = config_path.parent() {
        fs::create_dir_all(parent)?;
    }
    let common = git_common_dir.to_string_lossy();
    let now = chrono::Utc::now().format("%Y-%m-%d").to_string();
    let content = format!(
        "# Gerado automaticamente por `pks init` em {now}\n\n\
         [project]\nname = \"{name}\"\ngit_common_dir = \"{common}\"\n\n\
         [indexing]\nenabled = true\nwatch_paths = [\".\"]\n\
         ignore_patterns = [\"target/\", \"node_modules/\", \".git/\", \"dist/\", \"build/\", \"*.lock\"]\n\n\
         [journal]\nshadow_journaling = false\nmin_words_per_entry = 50\n\n\
         [embedding]\nprovider = \"none\"\n"
    );
    let mut file = OpenOptions::new().write(true).create(true).truncate(true).open(config_path)?;
    file.write_all(content.as_bytes())?;
    Ok(())
}

fn register_with_daemon(repo_id: &str) {
    let exe = std::env::current_exe().unwrap_or_else(|_| PathBuf::from("pks"));
    let output = Command::new(exe).args(["refresh"]).output();
    if let Ok(o) = output {
        if !o.status.success() {
            eprintln!("⚠ Daemon offline — {repo_id} será registrado na próxima inicialização.");
        }
    }
}

fn add_pks_to_exclude(git_root: &Path) -> Result<(), std::io::Error> {
    use std::fs::{self, OpenOptions};
    use std::io::Write;
    let exclude = git_root.join(".git").join("info").join("exclude");
    if let Some(p) = exclude.parent() { fs::create_dir_all(p)?; }
    let contents = fs::read_to_string(&exclude).unwrap_or_default();
    let mut f = OpenOptions::new().create(true).append(true).open(&exclude)?;
    if !contents.contains(".pks/") {
        writeln!(f, ".pks/")?;
    }
    if !contents.contains("prometheus/") {
        writeln!(f, "prometheus/")?;
    }
    Ok(())
}

fn hide_worktree_from_vscode(git_root: &Path) -> Result<(), std::io::Error> {
    use std::fs;
    let vscode_dir = git_root.join(".vscode");
    fs::create_dir_all(&vscode_dir)?;
    let settings_path = vscode_dir.join("settings.json");
    let mut obj: serde_json::Map<String, serde_json::Value> = if settings_path.exists() {
        let raw = fs::read_to_string(&settings_path)?;
        serde_json::from_str(&raw).unwrap_or_default()
    } else {
        serde_json::Map::new()
    };
    let key = "git.ignoredRepositories";
    let repos = obj.entry(key.to_string())
        .or_insert_with(|| serde_json::Value::Array(vec![]));
    if let serde_json::Value::Array(arr) = repos {
        let entry = serde_json::Value::String("prometheus".to_string());
        if !arr.contains(&entry) {
            arr.push(entry);
        }
    }
    fs::write(&settings_path, serde_json::to_string_pretty(&obj).unwrap())?;
    Ok(())
}

