use crate::hooks::journal_entry::{redact_secrets, truncate_summary};

/// Tools whose events are captured and journaled.
pub const CAPTURED_TOOLS: &[&str] = &["Edit", "Write", "MultiEdit", "Bash"];

/// Extracts file paths from `tool_input` based on the tool name.
pub fn extract_file_paths(tool_name: &str, tool_input: &serde_json::Value) -> Vec<String> {
    match tool_name {
        "Edit" | "Write" => {
            tool_input["file_path"]
                .as_str()
                .map(|s| vec![s.to_owned()])
                .unwrap_or_default()
        }
        "MultiEdit" => extract_multi_edit_paths(tool_input),
        _ => vec![],
    }
}

fn extract_multi_edit_paths(tool_input: &serde_json::Value) -> Vec<String> {
    if let Some(arr) = tool_input["edits"].as_array() {
        return arr
            .iter()
            .filter_map(|e| e["file_path"].as_str().map(str::to_owned))
            .collect();
    }
    tool_input["file_path"]
        .as_str()
        .map(|s| vec![s.to_owned()])
        .unwrap_or_default()
}

/// Builds a short human-readable summary of the tool input.
pub fn build_tool_input_summary(
    tool_name: &str,
    tool_input: &serde_json::Value,
    file_paths: &[String],
) -> String {
    match tool_name {
        "Edit" | "Write" => tool_input["file_path"]
            .as_str()
            .unwrap_or("(unknown)")
            .to_owned(),
        "Bash" => tool_input["command"]
            .as_str()
            .unwrap_or("bash command")
            .to_owned(),
        "MultiEdit" => {
            if file_paths.is_empty() { "multi-edit".to_owned() } else { file_paths.join(", ") }
        }
        _ => tool_name.to_owned(),
    }
}

/// Applies truncation and secret redaction to a raw summary string.
pub fn sanitize_summary(raw: &str) -> String {
    redact_secrets(truncate_summary(raw, 200))
}

mod helpers;
pub use helpers::{
    CAPTURED_TOOLS, build_tool_input_summary, extract_file_paths, sanitize_summary,
};

use std::io::Read;
use std::path::{Path, PathBuf};

use chrono::Utc;

use crate::hooks::hook_payload::PostToolUsePayload;
use crate::hooks::journal_entry::JournalEntry;

fn read_stdin() -> Result<String, std::io::Error> {
    let mut buf = String::new();
    std::io::stdin().read_to_string(&mut buf)?;
    Ok(buf)
}

fn append_entry(sessions_dir: &Path, session_id: &str, line: &str) -> Result<(), std::io::Error> {
    use std::fs::OpenOptions;
    use std::io::Write;

    std::fs::create_dir_all(sessions_dir)?;
    let path = sessions_dir.join(format!("{session_id}.jsonl"));
    let mut file = OpenOptions::new().create(true).append(true).open(path)?;
    writeln!(file, "{line}")?;
    Ok(())
}

fn build_entry(payload: &PostToolUsePayload) -> Option<JournalEntry> {
    if !CAPTURED_TOOLS.contains(&payload.tool_name.as_str()) {
        return None;
    }
    let file_paths = extract_file_paths(&payload.tool_name, &payload.tool_input);
    let raw = build_tool_input_summary(&payload.tool_name, &payload.tool_input, &file_paths);
    let tool_input_summary = sanitize_summary(&raw);
    let outcome = if payload.tool_response.success { "success" } else { "failure" };
    Some(JournalEntry {
        timestamp: Utc::now(),
        tool_name: payload.tool_name.clone(),
        tool_input_summary,
        outcome: outcome.to_owned(),
        file_paths,
        decision_note: None,
    })
}

/// Core implementation — accepts an explicit sessions directory for testability.
pub fn record_event_to_dir(sessions_dir: &Path) -> i32 {
    let raw = match read_stdin() {
        Ok(s) => s,
        Err(e) => { eprintln!("pks record-event: failed to read stdin: {e}"); return 0; }
    };

    let payload: PostToolUsePayload = match serde_json::from_str(&raw) {
        Ok(p) => p,
        Err(_) => return 0,
    };

    let entry = match build_entry(&payload) {
        Some(e) => e,
        None => return 0,
    };

    let line = match serde_json::to_string(&entry) {
        Ok(s) => s,
        Err(e) => { eprintln!("pks record-event: serialize error: {e}"); return 0; }
    };

    if let Err(e) = append_entry(sessions_dir, &payload.session_id, &line) {
        eprintln!("pks record-event: write error: {e}");
    }
    0
}

/// Entry point for `pks record-event`.
pub fn run_record_event() -> i32 {
    let home = std::env::var("HOME").unwrap_or_else(|_| "/tmp".to_string());
    let sessions_dir = PathBuf::from(home).join(".pks/sessions");
    record_event_to_dir(&sessions_dir)
}

