        let repo = make_git_dir(&dir);
        let check = check_io_latency(&repo);
        assert_eq!(check.name, "io:latency");
        assert_eq!(check.status, CheckStatus::Ok);
    }

    #[test]
    fn check_cloud_filesystem_ok_on_local() {
        let dir = TempDir::new().unwrap();
        let check = check_cloud_filesystem(dir.path());
        assert_eq!(check.name, "fs:cloud");
        assert_eq!(check.status, CheckStatus::Ok);
    }

    #[test]
    fn doctor_reports_missing_exclude_and_repairs() {
        let dir = TempDir::new().unwrap();
        let repo = make_git_dir(&dir);
        std::fs::write(repo.join(".git/info/exclude"), "").unwrap();
        let report = run_doctor(&repo);
        let check = report.checks.iter().find(|c| c.name.contains("exclude")).unwrap();
        assert_eq!(check.status, CheckStatus::Ok);
        assert!(check.repaired);
        let content = std::fs::read_to_string(repo.join(".git/info/exclude")).unwrap();
        assert!(content.contains("prometheus/"));
    }

    #[test]
    fn doctor_detects_missing_hook_and_installs() {
        let dir = TempDir::new().unwrap();
        let repo = make_git_dir(&dir);
        std::fs::write(repo.join(".git/info/exclude"), "prometheus/\n").unwrap();
        let report = run_doctor(&repo);
        let check = report.checks.iter().find(|c| c.name.contains("hook")).unwrap();
        assert_eq!(check.status, CheckStatus::Ok);
        assert!(check.repaired);
        let content = std::fs::read_to_string(repo.join(".git/hooks/post-commit")).unwrap();
        assert!(content.contains("pks hook-post-commit"));
    }

    #[test]
    fn report_exit_code_is_zero_when_all_ok() {
        let report = DoctorReport {
            checks: vec![
                DoctorCheck { name: "a", status: CheckStatus::Ok, repaired: false },
                DoctorCheck { name: "b", status: CheckStatus::Ok, repaired: true },
            ],
        };
        assert_eq!(report.exit_code(), 0);
        assert!(report.all_ok());
    }

    #[test]
    fn report_exit_code_is_one_when_errors() {
        let report = DoctorReport {
            checks: vec![
                DoctorCheck { name: "a", status: CheckStatus::Ok, repaired: false },
                DoctorCheck { name: "b", status: CheckStatus::Error("bad".to_string()), repaired: false },
            ],
        };
        assert_eq!(report.exit_code(), 1);
        assert!(!report.all_ok());
    }
}

use serde::Deserialize;

/// Active embedding provider, controlled by `PKS_EMBEDDING_PROVIDER`.
/// Default is `None` (BM25-only mode — no Ollama required).
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum EmbeddingProviderKind {
    None,
    Ollama,
    Mlx,
}

impl EmbeddingProviderKind {
    pub fn from_env() -> Self {
        match std::env::var("PKS_EMBEDDING_PROVIDER")
            .unwrap_or_default()
            .to_lowercase()
            .as_str()
        {
            "ollama" => EmbeddingProviderKind::Ollama,
            "mlx" => EmbeddingProviderKind::Mlx,
            _ => EmbeddingProviderKind::None,
        }
    }

    pub fn is_ollama(&self) -> bool {
        *self == EmbeddingProviderKind::Ollama
    }
}

#[derive(Debug)]
pub enum EmbeddingError {
    NetworkUnavailable(String),
    ModelNotFound(String),
    MalformedResponse(String),
    HttpRequestFailed(String),
}

impl std::fmt::Display for EmbeddingError {
    fn fmt(&self, formatter: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            EmbeddingError::NetworkUnavailable(msg) => write!(formatter, "network unavailable: {msg}"),
            EmbeddingError::ModelNotFound(msg) => write!(formatter, "model not found: {msg}"),
            EmbeddingError::MalformedResponse(msg) => write!(formatter, "malformed response: {msg}"),
            EmbeddingError::HttpRequestFailed(msg) => write!(formatter, "http request failed: {msg}"),
        }
    }
}

pub trait EmbeddingProvider {
    fn embed_text(
        &self,
        text: &str,
    ) -> impl std::future::Future<Output = Result<Vec<f32>, EmbeddingError>> + Send;
}

#[derive(Debug, Clone)]
pub struct OllamaProvider {
    pub base_url: String,
    pub model: String,
    pub throttle_ms: u64,
}

fn read_base_url() -> String {
    std::env::var("OLLAMA_BASE_URL")
        .unwrap_or_else(|_| "http://localhost:11434".to_string())
}

fn read_model() -> String {
    std::env::var("OLLAMA_EMBED_MODEL")
        .unwrap_or_else(|_| "nomic-embed-text".to_string())
}

fn read_throttle_ms() -> u64 {
    std::env::var("PKS_THROTTLE_MS")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(200u64)
}

impl OllamaProvider {
    pub fn from_env() -> Self {
        Self {
            base_url: read_base_url(),
            model: read_model(),
            throttle_ms: read_throttle_ms(),
        }
    }
}

#[derive(Deserialize)]
struct OllamaEmbeddingResponse {
    embedding: Vec<f32>,
}

async fn post_to_ollama(
    endpoint: &str,
    body: &serde_json::Value,
) -> Result<reqwest::Response, EmbeddingError> {
    reqwest::Client::new()
        .post(endpoint)
        .json(body)
        .send()
        .await
        .map_err(|err| EmbeddingError::NetworkUnavailable(err.to_string()))
}

async fn decode_embedding_response(
    response: reqwest::Response,
    model: &str,
) -> Result<Vec<f32>, EmbeddingError> {
    if response.status() == reqwest::StatusCode::NOT_FOUND {
        return Err(EmbeddingError::ModelNotFound(model.to_string()));
    }
    if !response.status().is_success() {
        return Err(EmbeddingError::HttpRequestFailed(response.status().to_string()));
    }
    response
        .json::<OllamaEmbeddingResponse>()
        .await
        .map(|r| r.embedding)
        .map_err(|err| EmbeddingError::MalformedResponse(err.to_string()))
}

impl EmbeddingProvider for OllamaProvider {
    async fn embed_text(&self, text: &str) -> Result<Vec<f32>, EmbeddingError> {
        let endpoint = format!("{}/api/embeddings", self.base_url);
        let body = serde_json::json!({"model": self.model, "prompt": text});
        let response = post_to_ollama(&endpoint, &body).await?;
        decode_embedding_response(response, &self.model).await
    }
}

