    fn summary_truncates_large_output() {
        let lines: Vec<&str> = (0..500).map(|_| "line of output").collect();
        let summary = build_summary(&lines, "errors", 5);
        assert!(summary.lines().count() <= MAX_SUMMARY_LINES);
    }

    #[test]
    fn extract_terms_returns_meaningful_words() {
        let text = "test failed assertion error in module validation_check";
        let terms = extract_terms(text, 5);
        assert!(!terms.is_empty());
        assert!(terms.iter().all(|t| t.len() >= 4));
    }
}

use std::collections::VecDeque;
use std::io::{BufRead, Write};
use std::path::PathBuf;

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq)]
pub enum OllamaState {
    Healthy,
    ModelMissing,
    TemporarilyOffline,
    ProlongedOffline,
    ReturnFromOffline,
}

#[derive(Serialize, Deserialize)]
struct DebtRecord {
    chunk_hash: String,
    vector: Vec<f32>,
}

pub struct FifoEmbedder {
    pub backlog: VecDeque<(String, Vec<f32>)>,
    pub state: OllamaState,
    pub debt_path: PathBuf,
    pub max_vectors: usize,
    pub hibernate_days: u64,
}

impl FifoEmbedder {
    pub fn from_env() -> Self {
        let max_vectors = std::env::var("PKS_MAX_VECTORS")
            .ok().and_then(|v| v.parse().ok()).unwrap_or(500_000usize);
        let hibernate_days = std::env::var("PKS_HIBERNATE_DAYS")
            .ok().and_then(|v| v.parse().ok()).unwrap_or(7u64);
        Self {
            backlog: VecDeque::new(),
            state: OllamaState::Healthy,
            debt_path: resolve_debt_path(),
            max_vectors,
            hibernate_days,
        }
    }

    pub fn enqueue_chunk(&mut self, chunk_hash: String, embedding: Vec<f32>) {
        self.backlog.push_back((chunk_hash, embedding));
    }

    pub fn backlog_depth(&self) -> usize {
        self.backlog.len()
    }

    pub fn serialize_overflow_to_debt(&mut self) {
        let parent = match self.debt_path.parent() {
            Some(p) => p.to_path_buf(),
            None => return,
        };
        if std::fs::create_dir_all(&parent).is_err() {
            return;
        }
        let file = match std::fs::OpenOptions::new()
            .create(true).append(true).open(&self.debt_path)
        {
            Ok(f) => f,
            Err(_) => return,
        };
        let mut writer = std::io::BufWriter::new(file);
        while let Some((chunk_hash, vector)) = self.backlog.pop_front() {
            let record = DebtRecord { chunk_hash, vector };
            if let Ok(line) = serde_json::to_string(&record) {
                let _ = writeln!(writer, "{line}");
            }
        }
    }

    pub fn drain_debt_file(&mut self) {
        if !self.debt_path.exists() {
            return;
        }
        let file = match std::fs::File::open(&self.debt_path) {
            Ok(f) => f,
            Err(_) => return,
        };
        let reader = std::io::BufReader::new(file);
        for line_result in reader.lines() {
            let line = match line_result { Ok(l) => l, Err(_) => continue };
            let record: DebtRecord = match serde_json::from_str(&line) {
                Ok(r) => r,
                Err(_) => continue,
            };
            self.backlog.push_back((record.chunk_hash, record.vector));
        }
        let _ = std::fs::remove_file(&self.debt_path);
    }
}

fn resolve_debt_path() -> PathBuf {
    let home = std::env::var("HOME").unwrap_or_else(|_| "/tmp".to_string());
    PathBuf::from(home).join(".pks").join("embedding_debt.jsonl")
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::Mutex;
    use tempfile::TempDir;

    static ENV_LOCK: Mutex<()> = Mutex::new(());

    fn embedder_in_dir(dir: &TempDir) -> FifoEmbedder {
        FifoEmbedder {
            backlog: VecDeque::new(),
            state: OllamaState::Healthy,
            debt_path: dir.path().join("embedding_debt.jsonl"),
            max_vectors: 500_000,
            hibernate_days: 7,
        }
    }

    #[test]
    fn from_env_creates_with_defaults() {
        let _guard = ENV_LOCK.lock().unwrap();
        std::env::remove_var("PKS_MAX_VECTORS");
        std::env::remove_var("PKS_HIBERNATE_DAYS");
        let embedder = FifoEmbedder::from_env();
        assert_eq!(embedder.max_vectors, 500_000);
        assert_eq!(embedder.hibernate_days, 7);
        assert_eq!(embedder.state, OllamaState::Healthy);
    }

    #[test]
    fn from_env_reads_custom_vars() {
        let _guard = ENV_LOCK.lock().unwrap();
        std::env::set_var("PKS_MAX_VECTORS", "1000");
        std::env::set_var("PKS_HIBERNATE_DAYS", "3");
        let embedder = FifoEmbedder::from_env();
        std::env::remove_var("PKS_MAX_VECTORS");
        std::env::remove_var("PKS_HIBERNATE_DAYS");
        assert_eq!(embedder.max_vectors, 1000);
        assert_eq!(embedder.hibernate_days, 3);
    }

    #[test]
    fn enqueue_chunk_increments_backlog_depth() {
        let dir = TempDir::new().unwrap();
        let mut embedder = embedder_in_dir(&dir);
        assert_eq!(embedder.backlog_depth(), 0);
        embedder.enqueue_chunk("hash-a".to_string(), vec![0.1, 0.2]);
        assert_eq!(embedder.backlog_depth(), 1);
        embedder.enqueue_chunk("hash-b".to_string(), vec![0.3]);
        assert_eq!(embedder.backlog_depth(), 2);
    }

    #[test]
    fn serialize_overflow_creates_file_and_empties_backlog() {
        let dir = TempDir::new().unwrap();
        let mut embedder = embedder_in_dir(&dir);
        embedder.enqueue_chunk("h1".to_string(), vec![1.0]);
        embedder.enqueue_chunk("h2".to_string(), vec![2.0]);
        embedder.serialize_overflow_to_debt();
        assert!(embedder.debt_path.exists());
        assert_eq!(embedder.backlog_depth(), 0);
    }

    #[test]
    fn drain_debt_file_reingests_and_removes_file() {
        let dir = TempDir::new().unwrap();
        let mut embedder = embedder_in_dir(&dir);
        embedder.enqueue_chunk("hx".to_string(), vec![9.0]);
        embedder.enqueue_chunk("hy".to_string(), vec![5.0]);
        embedder.serialize_overflow_to_debt();
        embedder.drain_debt_file();
        assert_eq!(embedder.backlog_depth(), 2);
        assert!(!embedder.debt_path.exists());
    }

    #[test]
    fn drain_debt_file_absent_file_is_noop() {
        let dir = TempDir::new().unwrap();
        let mut embedder = embedder_in_dir(&dir);
        embedder.drain_debt_file();
        assert_eq!(embedder.backlog_depth(), 0);
    }

    #[test]
    fn ollama_state_has_five_distinct_variants() {
        assert_ne!(OllamaState::Healthy, OllamaState::ModelMissing);
        assert_ne!(OllamaState::TemporarilyOffline, OllamaState::ProlongedOffline);
        assert_ne!(OllamaState::ProlongedOffline, OllamaState::ReturnFromOffline);
    }
}

use tokio::sync::mpsc;

use crate::debounce::Debouncer;
use crate::embedding_provider::{EmbeddingProvider, OllamaProvider};
use crate::indexer::pipeline::IndexingPipeline;
use crate::search::retriever::{SearchBackend, TantivyBackend};
use crate::state::{IndexMutation, PipelineEvent, RawTransaction};

fn fila1_capacity() -> usize {
    std::env::var("PKS_FILA1_MAX")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(1000)
}

fn fila2_capacity() -> usize {
    std::env::var("PKS_FILA2_MAX")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(500)
}

async fn mutation_from_event(
    event: PipelineEvent,
    pipeline: &mut IndexingPipeline,
    embedder: &impl EmbeddingProvider,
) -> IndexMutation {
    match event {
        PipelineEvent::FileChanged { repo_id, file_path, content } => {
            let tagged_chunks = pipeline.process_file_with_dirty_markers(&repo_id, &file_path, &content);
            let mut results = Vec::new();
            for (chunk, is_dirty) in tagged_chunks {
                if is_dirty {
                    match embedder.embed_text(&chunk.text).await {
                        Ok(vec) => results.push((chunk, Some(vec))),
                        Err(_) => results.push((chunk, None)), // Degradation
                    }
                } else {
                    results.push((chunk, None)); // Reuse stored if exists or stay lazy
                }
            }
            IndexMutation::AddChunks(results)
        }
        PipelineEvent::FileDeleted { repo_id, file_path } => {
            IndexMutation::RemoveFile { repo_id, file_path }
        }
        PipelineEvent::RepoRegistered { .. } => IndexMutation::AddChunks(vec![]),
        PipelineEvent::RepoDeregistered { repo_id, .. } => {
            IndexMutation::RemoveFile { repo_id, file_path: String::new() }
        }
    }
}

async fn run_background_consumer(
    mut ingest_rx: mpsc::Receiver<RawTransaction>,
    mutations_tx: mpsc::Sender<IndexMutation>,
    mut pipeline: IndexingPipeline,
) {
    let mut debouncer = Debouncer::new_from_env();
    let embedder = OllamaProvider::from_env();
    while let Some(tx) = ingest_rx.recv().await {
        let key = Debouncer::make_dedup_key(
            tx.commit_sha.as_deref(),
            tx.tree_hash.as_deref(),
        );
        if debouncer.is_duplicate_and_record(&key) {
            continue;
        }
        let mutation = mutation_from_event(tx.event, &mut pipeline, &embedder).await;
        let _ = mutations_tx.try_send(mutation);
    }
}

pub struct FifoPipeline {
    ingest_tx: mpsc::Sender<RawTransaction>,
    mutations_rx: mpsc::Receiver<IndexMutation>,
}

impl FifoPipeline {
    pub fn new_and_spawn() -> Self {
        let (ingest_tx, ingest_rx) = mpsc::channel::<RawTransaction>(fila1_capacity());
        let (mutations_tx, mutations_rx) = mpsc::channel::<IndexMutation>(fila2_capacity());
        let pipeline = IndexingPipeline::new_from_env();
        tokio::spawn(run_background_consumer(ingest_rx, mutations_tx, pipeline));
        Self { ingest_tx, mutations_rx }
    }

    pub fn submit_transaction_to_ingest_queue(&self, tx: RawTransaction) {
        let _ = self.ingest_tx.try_send(tx);
    }

    pub fn drain_pending_mutations(&mut self, backend: &mut TantivyBackend) {
        let mut did_write = false;
        while let Ok(mutation) = self.mutations_rx.try_recv() {
            apply_mutation_to_backend(mutation, backend);
            did_write = true;
        }
        if did_write {
            let _ = backend.commit();
        }
    }
}

fn apply_mutation_to_backend(mutation: IndexMutation, backend: &mut TantivyBackend) {
    match mutation {
        IndexMutation::AddChunks(chunks_with_vecs) => {
            for (chunk, vector) in chunks_with_vecs {
                if chunk.is_tombstone {
                    let _ = backend.remove_chunks_for_file(&chunk.repo_id, &chunk.file_path);
                    continue;
                }
                if let Some(v) = vector {
                    let _ = backend.add_chunk_with_vector(&chunk, v);
                } else {
                    let _ = backend.add_chunk(&chunk);
                }
            }
        }
        IndexMutation::RemoveFile { repo_id, file_path } => {
            if !file_path.is_empty() {
                let _ = backend.remove_chunks_for_file(&repo_id, &file_path);
            }
        }
    }
}

use std::path::PathBuf;
use git2::{Repository, Signature};

pub const PKS_BRANCH: &str = "pks-knowledge";

/// Writes files directly to the `pks-knowledge` git branch
/// using git2 plumbing — zero effect on the working tree or index.
pub struct BareCommit {
    repo_path: PathBuf,
}

impl BareCommit {
    pub fn new(repo_path: impl Into<PathBuf>) -> Self {
        Self { repo_path: repo_path.into() }
    }

    /// Ensures the `pks-knowledge` branch exists.
    /// Creates it with an empty root commit if it doesn't.
    pub fn ensure_branch(&self) -> Result<(), git2::Error> {
        let repo = Repository::open(&self.repo_path)?;
        self.ensure_branch_on_repo(&repo)
    }

    /// Writes `content` at `file_path` within the `pks-knowledge` branch.
    /// Does NOT touch the working tree or the index.
    pub fn write_file(
        &self,
        file_path: &str,
        content: &[u8],
        message: &str,
    ) -> Result<git2::Oid, git2::Error> {
        let repo = Repository::open(&self.repo_path)?;
        self.ensure_branch_on_repo(&repo)?;
        let blob_oid = repo.blob(content)?;
        let branch_ref = repo.find_branch(PKS_BRANCH, git2::BranchType::Local)?;
        let parent_commit = branch_ref.get().peel_to_commit()?;
        let parent_tree = parent_commit.tree()?;
        let new_tree_oid = build_tree_with_file(&repo, Some(&parent_tree), file_path, blob_oid)?;
        let new_tree = repo.find_tree(new_tree_oid)?;
        let sig = bot_sig(&repo);
        repo.commit(
            Some(&format!("refs/heads/{PKS_BRANCH}")),
            &sig,
            &sig,
            message,
            &new_tree,
            &[&parent_commit],
        )
    }

    fn ensure_branch_on_repo(&self, repo: &Repository) -> Result<(), git2::Error> {
        if repo.find_branch(PKS_BRANCH, git2::BranchType::Local).is_ok() {
            return Ok(());
        }
        let tree_oid = repo.treebuilder(None)?.write()?;
        let tree = repo.find_tree(tree_oid)?;
        let sig = bot_sig(repo);
        repo.commit(
            Some(&format!("refs/heads/{PKS_BRANCH}")),
            &sig,
            &sig,
            "chore(pks): initialize pks-knowledge branch",
            &tree,
            &[],
        )?;
        Ok(())
    }
}

fn bot_sig(repo: &Repository) -> Signature<'static> {
    repo.signature()
        .unwrap_or_else(|_| Signature::now("pks-bot", "pks@localhost").unwrap())
}

/// Inserts `file_path` (possibly nested, e.g. `dir/sub/file.md`) with `blob_oid`
/// into a new tree based on `parent_tree`. Handles arbitrary depth recursively.
fn build_tree_with_file(
    repo: &Repository,
    parent_tree: Option<&git2::Tree>,
    file_path: &str,
    blob_oid: git2::Oid,
) -> Result<git2::Oid, git2::Error> {
    match file_path.split_once('/') {
        None => {
            let mut builder = repo.treebuilder(parent_tree)?;
            builder.insert(file_path, blob_oid, 0o100644)?;
            builder.write()
        }
        Some((dir_name, rest)) => {
            let existing_subtree = parent_tree
                .and_then(|t| t.get_name(dir_name))
                .and_then(|e| repo.find_tree(e.id()).ok());
            let new_subtree_oid = build_tree_with_file(
                repo,
                existing_subtree.as_ref(),
                rest,
                blob_oid,
            )?;
            let mut builder = repo.treebuilder(parent_tree)?;
            builder.insert(dir_name, new_subtree_oid, 0o040000)?;
            builder.write()
        }
    }
}

