mod tests {
    use super::*;

    fn section_heading(index: usize) -> String {
        format!("## Section {}", index)
    }

    fn section_body(index: usize) -> String {
        format!(
            "Section {} contains stable body content designed to exceed the minimum token threshold. \
            This paragraph provides enough words so that the chunker treats each heading section as \
            its own independent chunk without merging adjacent sections together. \
            Unique marker alpha-{} beta-{} gamma-{} ensures hash distinctness.",
            index, index, index, index
        )
    }

    fn build_headed_document(bodies: &[String]) -> String {
        bodies
            .iter()
            .enumerate()
            .map(|(i, body)| format!("{}\n\n{}", section_heading(i), body))
            .collect::<Vec<_>>()
            .join("\n\n")
    }

    #[test]
    fn new_file_all_chunks_are_dirty() {
        let mut pipeline = IndexingPipeline::new_from_env();
        let bodies: Vec<String> = (0..5).map(|i| section_body(i)).collect();
        let content = build_headed_document(&bodies);

        let tagged = pipeline.process_file_with_dirty_markers("repo", "file.md", &content);

        assert!(!tagged.is_empty());
        assert!(tagged.iter().all(|(_, dirty)| *dirty));
    }

    #[test]
    fn unchanged_file_has_no_dirty_chunks() {
        let mut pipeline = IndexingPipeline::new_from_env();
        let bodies: Vec<String> = (0..5).map(|i| section_body(i)).collect();
        let content = build_headed_document(&bodies);

        pipeline.process_file_with_dirty_markers("repo", "file.md", &content);
        let second = pipeline.process_file_with_dirty_markers("repo", "file.md", &content);

        assert!(second.iter().all(|(_, dirty)| !dirty));
    }

    #[test]
    fn editing_one_paragraph_marks_only_affected_chunks_as_dirty() {
        let mut pipeline = IndexingPipeline::new_from_env();
        let mut bodies: Vec<String> = (0..5).map(|i| section_body(i)).collect();
        let original = build_headed_document(&bodies);

        let first = pipeline.process_file_with_dirty_markers("repo", "file.md", &original);
        assert!(first.iter().all(|(_, dirty)| *dirty));

        bodies[2] = "EDITED body for section 2 completely rewritten with different unique words here.".to_string();
        let modified = build_headed_document(&bodies);

        let second = pipeline.process_file_with_dirty_markers("repo", "file.md", &modified);

        let dirty_count = second.iter().filter(|(_, dirty)| *dirty).count();
        let clean_count = second.iter().filter(|(_, dirty)| !dirty).count();

        assert!(dirty_count >= 1, "At least one chunk must be dirty after edit");
        assert!(clean_count >= 1, "At least one chunk must remain clean");
    }
}

mod server;

pub use server::IpcServer;

use serde::{Deserialize, Serialize};

/// Path to the Unix Domain Socket
pub const SOCKET_PATH: &str = "/tmp/pks.sock";

/// IPC protocol version — bump when breaking changes are made
pub const IPC_VER: u32 = 3;

/// Commands sent from client to daemon
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "cmd", content = "payload")]
pub enum PksCommand {
    Ping,
    Search {
        query: String,
        repo_id: Option<String>,
        top_n: usize,
    },
    ListVaults,
    Refresh {
        dry_run: bool,
    },
    Remove {
        repo_id: String,
    },
}

/// Responses sent from daemon to client
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "status", content = "data")]
pub enum PksResponse {
    Pong { ver: u32 },
    SearchResults { hits: Vec<SearchHit> },
    VaultList { vaults: Vec<String> },
    RefreshDone {
        added: Vec<String>,
        removed: Vec<String>,
        unchanged: Vec<String>,
    },
    RemoveDone { repo_id: String },
    Err { message: String },
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SearchHit {
    pub repo_id: String,
    pub file_path: String,
    pub score: f32,
    pub snippet: String,
}

/// Client for sending commands to the daemon
pub struct IpcClient;

impl IpcClient {
    /// Returns true if the daemon at `SOCKET_PATH` responds to Ping within 200ms
    pub async fn is_server_running() -> bool {
        Self::is_server_running_at(SOCKET_PATH).await
    }

    /// Returns true if the daemon at `socket_path` responds to Ping within 200ms
    pub async fn is_server_running_at(socket_path: &str) -> bool {
        use std::time::Duration;
        use tokio::time::timeout;
        let result = timeout(
            Duration::from_millis(200),
            Self::try_ping_at(socket_path),
        )
        .await;
        matches!(result, Ok(Ok(_)))
    }

    async fn try_ping_at(socket_path: &str) -> Result<(), String> {
        match Self::send_command_to(&PksCommand::Ping, socket_path).await? {
            PksResponse::Pong { .. } => Ok(()),
            _ => Err("unexpected response to Ping".to_string()),
        }
    }

    /// Send a command to the daemon at `SOCKET_PATH`
    pub async fn send_command(cmd: &PksCommand) -> Result<PksResponse, String> {
        Self::send_command_to(cmd, SOCKET_PATH).await
    }

    /// Send a command to the daemon at the given `socket_path`
    pub async fn send_command_to(cmd: &PksCommand, socket_path: &str) -> Result<PksResponse, String> {
        use std::time::Duration;
        use tokio::time::timeout;
        timeout(Duration::from_millis(5000), Self::do_send(cmd, socket_path))
            .await
            .map_err(|_| "daemon timeout".to_string())?
    }

    #[cfg(unix)]
    async fn do_send(cmd: &PksCommand, socket_path: &str) -> Result<PksResponse, String> {
        use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
        use tokio::net::UnixStream;
        let mut stream = UnixStream::connect(socket_path)
            .await
            .map_err(|_| "daemon not running".to_string())?;
        let mut line = serde_json::to_string(cmd)
            .map_err(|e| format!("serialization error: {e}"))?;
        line.push('\n');
        stream.write_all(line.as_bytes()).await.map_err(|e| format!("write error: {e}"))?;
        let mut reader = BufReader::new(stream);
        let mut response_line = String::new();
        reader.read_line(&mut response_line).await.map_err(|e| format!("read error: {e}"))?;
        serde_json::from_str(response_line.trim())
            .map_err(|e| format!("deserialization error: {e}"))
    }

    #[cfg(not(unix))]
    async fn do_send(_cmd: &PksCommand, _socket_path: &str) -> Result<PksResponse, String> {
        Err("Unix Domain Sockets are only supported on Unix platforms".to_string())
    }
}

