pub struct McpServer {
    addr: SocketAddr,
    cancellation_token: CancellationToken,
}

impl McpServer {
    pub fn new(port: u16) -> Self {
        let addr = SocketAddr::from(([127, 0, 0, 1], port));
        Self {
            addr,
            cancellation_token: CancellationToken::new(),
        }
    }

    pub fn port_from_env() -> u16 {
        env::var("PKS_PORT")
            .ok()
            .and_then(|v| v.parse().ok())
            .unwrap_or(DEFAULT_PORT)
    }

    pub fn bind_addr(&self) -> SocketAddr {
        self.addr
    }

    pub async fn run(
        self,
        state: Arc<Mutex<crate::state::PrevalentState>>,
    ) -> std::io::Result<()> {
        use axum::Router;
        use axum::routing::get;
        use rmcp::transport::streamable_http_server::session::local::LocalSessionManager;
        use rmcp::transport::streamable_http_server::{StreamableHttpServerConfig, StreamableHttpService};

        let ct = self.cancellation_token.clone();
        let config = StreamableHttpServerConfig { cancellation_token: ct.child_token(), ..Default::default() };
        let health_state = Arc::clone(&state);
        let service: StreamableHttpService<PksHandler, LocalSessionManager> = StreamableHttpService::new(
            move || Ok(PksHandler::new(Arc::clone(&state))),
            Arc::new(LocalSessionManager::default()),
            config,
        );
        let router = Router::new()
            .nest_service("/sse", service)
            .route("/health", get(health_handler))
            .with_state(health_state);
        let listener = TcpListener::bind(self.addr).await?;
        axum::serve(listener, router)
            .with_graceful_shutdown(async move { ct.cancelled_owned().await })
            .await
    }

    pub fn cancellation_token(&self) -> CancellationToken {
        self.cancellation_token.clone()
    }
}

use std::path::Path;

use crate::indexer::pipeline::IndexingPipeline;
use crate::search::retriever::{SearchBackend, TantivyBackend};
use crate::snapshot::SnapshotManager;

pub struct MemoryManager;

impl MemoryManager {
    pub fn load_repo(
        repo_id: &str,
        repo_path: &Path,
        pipeline: &IndexingPipeline,
        backend: &mut TantivyBackend,
    ) -> usize {
        let md_files = collect_md_files(repo_path);
        let mut chunk_count = 0;

        for file_path in &md_files {
            let Ok(content) = std::fs::read_to_string(file_path) else {
                continue;
            };
            let rel = file_path
                .strip_prefix(repo_path)
                .map(|p| p.to_string_lossy().into_owned())
                .unwrap_or_else(|_| file_path.to_string_lossy().into_owned());

            let chunks = pipeline.process_file(repo_id, &rel, &content);
            chunk_count += chunks.len();
            for chunk in &chunks {
                let _ = backend.add_chunk(chunk);
            }
        }

        let _ = backend.commit();
        chunk_count
    }

    pub fn unload_repo(
        repo_id: &str,
        backend: &mut TantivyBackend,
        snapshot_manager: &SnapshotManager,
    ) {
        let _ = remove_all_chunks_for_repo(repo_id, backend);
        let _ = backend.commit();
        let _ = snapshot_manager.delete_snapshot_for_repo(repo_id);
    }
}

pub fn collect_md_files_pub(dir: &Path) -> Vec<std::path::PathBuf> {
    collect_md_files(dir)
}

fn collect_md_files(dir: &Path) -> Vec<std::path::PathBuf> {
    let mut result = Vec::new();
    collect_md_files_inner(dir, &mut result);
    result
}

fn is_hidden_dir(path: &std::path::Path) -> bool {
    path.is_dir()
        && path
            .file_name()
            .map(|n| n.to_string_lossy().starts_with('.'))
            .unwrap_or(false)
}

fn collect_md_files_inner(dir: &Path, out: &mut Vec<std::path::PathBuf>) {
    let Ok(entries) = std::fs::read_dir(dir) else {
        return;
    };
    for entry in entries.filter_map(|e| e.ok()) {
        let path = entry.path();
        if is_hidden_dir(&path) {
            continue;
        }
        if path.is_dir() {
            collect_md_files_inner(&path, out);
            continue;
        }
        if path.extension().map(|e| e == "md").unwrap_or(false) {
            out.push(path);
        }
    }
}

fn remove_all_chunks_for_repo(
    repo_id: &str,
    backend: &mut TantivyBackend,
) -> tantivy::Result<()> {
    backend.remove_chunks_for_repo(repo_id)
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    fn make_repo(dir: &TempDir, files: &[(&str, &str)]) -> std::path::PathBuf {
        let repo = dir.path().join("repo");
        std::fs::create_dir_all(repo.join(".git")).unwrap();
        for (name, content) in files {
            std::fs::write(repo.join(name), content).unwrap();
        }
        repo
    }

    #[test]
    fn load_repo_indexes_md_files() {
        let dir = TempDir::new().unwrap();
        let repo = make_repo(&dir, &[
            ("README.md", "# Hello\n\nThis is a test note about indexing."),
            ("notes.md", "# Notes\n\nSome content here."),
            ("ignored.txt", "not markdown"),
        ]);

        let pipeline = IndexingPipeline::new_from_env();
        let mut backend = TantivyBackend::new_in_memory().unwrap();

        let count = MemoryManager::load_repo("test-repo", &repo, &pipeline, &mut backend);
        assert!(count >= 2, "expected at least 2 chunks from 2 md files, got {count}");
    }

    #[test]
    fn unload_repo_deletes_snapshot() {
        let dir = TempDir::new().unwrap();
        let snap_mgr = SnapshotManager::new_with_dir(dir.path().to_path_buf());

        let data = crate::snapshot::SnapshotData {
            repo_id: "repo-x".to_string(),
            chunks: vec![],
            vector_clock_sha: "abc".to_string(),
            created_at_secs: 0,
        };
        snap_mgr.write_snapshot_for_repo(&data).unwrap();
        assert!(snap_mgr.snapshot_file_path("repo-x").exists());

        let mut backend = TantivyBackend::new_in_memory().unwrap();
        MemoryManager::unload_repo("repo-x", &mut backend, &snap_mgr);

        assert!(!snap_mgr.snapshot_file_path("repo-x").exists());
    }

    #[test]
    fn collect_md_skips_hidden_dirs() {
        let dir = TempDir::new().unwrap();
        let base = dir.path();
        std::fs::create_dir_all(base.join(".git")).unwrap();
        std::fs::write(base.join(".git/COMMIT_EDITMSG"), "ignore me").unwrap();
        std::fs::write(base.join("visible.md"), "# Visible").unwrap();

        let files = collect_md_files(base);
        assert_eq!(files.len(), 1);
        assert!(files[0].ends_with("visible.md"));
    }
}

/// Reflexive Global Memory writer — T4.7 (F2.6)
///
/// Writes AI session summaries to `prometheus/journals/YYYY-MM-DD.md`
/// in the pks-knowledge branch. Committed with source_commit_sha for
/// bidirectional traceability (code <-> context).
///
/// Trigger: explicit MCP tool call `pks_session_summary(session_context)`.
use std::path::Path;
use tracing::info;

#[derive(Debug)]
pub struct SessionSummary {
    pub date: String,
    pub session_sha: String,
    pub topics: Vec<String>,
    pub repos_touched: Vec<String>,
    pub decisions: Vec<String>,
    pub context: String,
    pub next_steps: Vec<String>,
}

impl SessionSummary {
    /// Render the session summary as a Markdown document with YAML frontmatter.
    pub fn render(&self) -> String {
        let topics = self.topics.join(", ");
        let repos = self.repos_touched.join(", ");

        let decisions = if self.decisions.is_empty() {
            "- (nenhuma decisao registrada)".to_string()
        } else {
            self.decisions.iter().map(|d| format!("- {d}")).collect::<Vec<_>>().join("\n")
        };

        let next_steps = if self.next_steps.is_empty() {
            "- (nenhum proximo passo registrado)".to_string()
        } else {
            self.next_steps.iter().map(|s| format!("- {s}")).collect::<Vec<_>>().join("\n")
        };

        format!(
            "---\n\
             session_sha: {sha}\n\
             date: {date}\n\
             topics: [{topics}]\n\
             repos_touched: [{repos}]\n\
             ---\n\n\
             # Memoria de Sessao — {date}\n\n\
             ## Decisoes\n\n\
             {decisions}\n\n\
             ## Contexto\n\n\
             {ctx}\n\n\
             ## Proximos Passos\n\n\
             {next_steps}\n",
            sha = self.session_sha,
            date = self.date,
            topics = topics,
            repos = repos,
            ctx = self.context,
            decisions = decisions,
            next_steps = next_steps,
        )
    }

    /// File path relative to the prometheus/ root (journals/YYYY-MM-DD.md).
    pub fn file_rel_path(&self) -> String {
        format!("journals/{}.md", self.date)
    }
}

/// Write a session summary to the prometheus/ worktree and commit it
/// to the `pks-knowledge` branch.
pub fn write_session_memory(
    prometheus_root: &Path,
    summary: &SessionSummary,
    source_commit_sha: &str,
) -> Result<(), String> {
    let content = summary.render();
    let file_rel = summary.file_rel_path();
    let message = format!("feat(pks-knowledge): session memory {}", summary.date);

    crate::git_branch::commit_to_pks_knowledge(
        prometheus_root,
        &file_rel,
        &content,
        source_commit_sha,
        &message,
    )
    .map_err(|e| e.to_string())?;

    info!(
        date = %summary.date,
        sha = %source_commit_sha,
        "session memory committed to pks-knowledge"
    );
    Ok(())
}

/// Pure rendering: produce summary Markdown without writing to disk.
/// Used by MCP tool `pks_session_summary`.
pub fn render_session_summary(summary: &SessionSummary) -> String {
    summary.render()
}

