use std::collections::HashSet;
use std::path::Path;

use sha2::{Digest, Sha256};

use crate::indexer::chunker::Chunk;
use crate::indexer::pipeline::IndexingPipeline;
use crate::search::retriever::{SearchBackend, TantivyBackend};
use crate::snapshot::SnapshotData;

pub fn restore_chunks_from_snapshot(
    repo_id: &str,
    snapshot: &SnapshotData,
    backend: &mut TantivyBackend,
) {
    for record in &snapshot.chunks {
        let chunk = Chunk {
            repo_id: repo_id.to_string(),
            file_path: record.file_path.clone(),
            heading_hierarchy: record.heading_hierarchy.clone(),
            chunk_index: record.chunk_index,
            chunk_hash: record.chunk_hash.clone(),
            text: record.chunk_text.clone(),
            is_tombstone: false,
        };
        let _ = backend.add_chunk(&chunk);
    }
    let _ = backend.commit();
}

fn needs_reindex(rel: &str, content_hash: &str, snapshot: &SnapshotData) -> bool {
    let in_snapshot = snapshot.chunks.iter().any(|c| c.file_path == rel);
    let hash_matches = snapshot
        .chunks
        .iter()
        .any(|c| c.file_path == rel && c.chunk_hash == content_hash);
    !in_snapshot || !hash_matches
}

fn reindex_file(
    repo_id: &str,
    rel: &str,
    content: &str,
    pipeline: &IndexingPipeline,
    backend: &mut TantivyBackend,
) {
    let _ = backend.remove_chunks_for_file(repo_id, rel);
    for chunk in pipeline.process_file(repo_id, rel, content) {
        let _ = backend.add_chunk(&chunk);
    }
}

fn content_hash(content: &str) -> String {
    format!("{:x}", Sha256::digest(content.as_bytes()))
}

fn rel_path(file_path: &Path, repo_path: &Path) -> String {
    file_path
        .strip_prefix(repo_path)
        .map(|p| p.to_string_lossy().into_owned())
        .unwrap_or_else(|_| file_path.to_string_lossy().into_owned())
}

fn reindex_changed_files(
    repo_id: &str,
    repo_path: &Path,
    snapshot: &SnapshotData,
    pipeline: &IndexingPipeline,
    backend: &mut TantivyBackend,
) -> bool {
    let md_files = crate::memory_manager::collect_md_files_pub(repo_path);
    let mut did_write = false;
    for file_path in &md_files {
        let Ok(content) = std::fs::read_to_string(file_path) else {
            continue;
        };
        let rel = rel_path(file_path, repo_path);
        let hash = content_hash(&content);
        if !needs_reindex(&rel, &hash, snapshot) {
            continue;
        }
        reindex_file(repo_id, &rel, &content, pipeline, backend);
        did_write = true;
    }
    did_write
}

fn remove_deleted_snapshot_files(
    repo_id: &str,
    repo_path: &Path,
    snapshot_paths: HashSet<&str>,
    backend: &mut TantivyBackend,
) -> bool {
    let mut did_write = false;
    for path in snapshot_paths {
        let full = repo_path.join(path);
        if full.exists() {
            continue;
        }
        let _ = backend.remove_chunks_for_file(repo_id, path);
        did_write = true;
    }
    did_write
}

pub fn reconcile_with_head(
    repo_id: &str,
    repo_path: &Path,
    snapshot: &SnapshotData,
    pipeline: &IndexingPipeline,
    backend: &mut TantivyBackend,
) {
    let snapshot_paths: HashSet<&str> =
        snapshot.chunks.iter().map(|c| c.file_path.as_str()).collect();

    let wrote_reindex = reindex_changed_files(repo_id, repo_path, snapshot, pipeline, backend);
    let wrote_delete =
        remove_deleted_snapshot_files(repo_id, repo_path, snapshot_paths, backend);

    if wrote_reindex || wrote_delete {
        let _ = backend.commit();
    }
}

use std::collections::HashMap;
use std::path::{Path, PathBuf};
use std::sync::mpsc;
use std::time::{Duration, Instant};
use tracing::{info, warn};

use crate::git_journal::CommitInfo;

fn poll_interval() -> Duration {
    let secs = std::env::var("PKS_REMOTE_POLL_INTERVAL")
        .ok()
        .and_then(|v| v.parse::<u64>().ok())
        .unwrap_or(300);
    Duration::from_secs(secs)
}

pub struct RemoteSync {
    last_fetched: HashMap<PathBuf, Instant>,
    poll_interval: Duration,
    commit_tx: mpsc::SyncSender<CommitInfo>,
}

impl RemoteSync {
    pub fn new(commit_tx: mpsc::SyncSender<CommitInfo>) -> Self {
        Self {
            last_fetched: HashMap::new(),
            poll_interval: poll_interval(),
            commit_tx,
        }
    }

    pub fn poll_all(&mut self, vaults_dir: &Path) {
        let Ok(entries) = std::fs::read_dir(vaults_dir) else {
            return;
        };
        for entry in entries.filter_map(|e| e.ok()) {
            let path = entry.path();
            if !path.is_dir() || !path.join(".git").is_dir() {
                continue;
            }
            if self.needs_fetch(&path) {
                self.fetch_repo(&path);
            }
        }
    }

    fn needs_fetch(&self, repo_path: &Path) -> bool {
        match self.last_fetched.get(repo_path) {
            None => true,
            Some(&last) => last.elapsed() >= self.poll_interval,
        }
    }

    fn fetch_repo(&mut self, repo_path: &Path) {
        let repo_id = repo_path
            .file_name()
            .map(|n| n.to_string_lossy().into_owned())
            .unwrap_or_else(|| repo_path.to_string_lossy().into_owned());

        let pre_sha = get_head_sha(repo_path);
        let result = git_fetch(repo_path);
        self.last_fetched.insert(repo_path.to_path_buf(), Instant::now());

        match result {
            Ok(_) => {
                info!(repo_id = %repo_id, "git fetch succeeded");
                let post_sha = get_head_sha(repo_path);
                if pre_sha != post_sha {
                    if let Some(sha) = post_sha {
                        let branch = get_current_branch(repo_path).unwrap_or_else(|| "main".to_string());
                        let info = CommitInfo {
                            repo_id,
                            repo_path: repo_path.to_path_buf(),
                            branch,
                            commit_sha: sha,
                            tree_hash: None,
                        };
                        let _ = self.commit_tx.try_send(info);
                    }
                }
            }
            Err(e) => {
                warn!(repo_id = %repo_id, error = %e, "git fetch failed — partition isolated");
            }
        }
    }
}

fn make_clone_url(url: &str) -> String {
    let Ok(token) = std::env::var("GITHUB_TOKEN") else {
        return url.to_string();
    };
    if !url.starts_with("https://github.com") {
        return url.to_string();
    }
    url.replace("https://github.com", &format!("https://{token}@github.com"))
}

pub fn clone_remote_repo(url: &str, vaults_dir: &Path, name: &str) -> Result<PathBuf, String> {
    let dest = vaults_dir.join(name);
    if dest.exists() {
        return Ok(dest);
    }
    let mut cmd = std::process::Command::new("git");
    cmd.current_dir(vaults_dir).arg("clone").arg(&make_clone_url(url)).arg(name);
    let output = cmd.output().map_err(|e| e.to_string())?;
    if !output.status.success() {
        return Err(String::from_utf8_lossy(&output.stderr).into_owned());
    }
    Ok(dest)
}

fn git_fetch(repo_path: &Path) -> Result<(), String> {
    let output = std::process::Command::new("git")
        .current_dir(repo_path)
        .args(["fetch", "--quiet", "--all"])
        .output()
        .map_err(|e| e.to_string())?;
    if !output.status.success() {
        return Err(String::from_utf8_lossy(&output.stderr).into_owned());
    }
    Ok(())
}

fn get_head_sha(repo_path: &Path) -> Option<String> {
    let output = std::process::Command::new("git")
        .current_dir(repo_path)
        .args(["rev-parse", "HEAD"])
        .output()
        .ok()?;
    if !output.status.success() {
        return None;
    }
    Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
}

fn get_current_branch(repo_path: &Path) -> Option<String> {
    let output = std::process::Command::new("git")
        .current_dir(repo_path)
        .args(["rev-parse", "--abbrev-ref", "HEAD"])
        .output()
        .ok()?;
    if !output.status.success() {
        return None;
    }
    Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
}

