use serde::Deserialize;

const NOTION_API_BASE: &str = "https://api.notion.com/v1";
const NOTION_VERSION: &str = "2022-06-28";

#[derive(Debug, Deserialize)]
pub struct NotionPage {
    pub id: String,
    pub properties: serde_json::Value,
}

#[derive(Debug, Deserialize)]
pub struct NotionBlock {
    #[serde(rename = "type")]
    pub block_type: String,
    #[serde(flatten)]
    pub data: serde_json::Value,
}

#[derive(Debug, Deserialize)]
struct BlocksResponse {
    results: Vec<NotionBlock>,
}

pub async fn fetch_page(page_id: &str, token: &str) -> Result<NotionPage, String> {
    let url = format!("{NOTION_API_BASE}/pages/{page_id}");
    let resp = reqwest::Client::new()
        .get(&url)
        .bearer_auth(token)
        .header("Notion-Version", NOTION_VERSION)
        .send()
        .await
        .map_err(|e| e.to_string())?;

    if !resp.status().is_success() {
        return Err(resp.text().await.unwrap_or_default());
    }
    resp.json::<NotionPage>().await.map_err(|e| e.to_string())
}

pub async fn fetch_blocks(page_id: &str, token: &str) -> Result<Vec<NotionBlock>, String> {
    let url = format!("{NOTION_API_BASE}/blocks/{page_id}/children");
    let resp = reqwest::Client::new()
        .get(&url)
        .bearer_auth(token)
        .header("Notion-Version", NOTION_VERSION)
        .send()
        .await
        .map_err(|e| e.to_string())?;

    if !resp.status().is_success() {
        return Err(resp.text().await.unwrap_or_default());
    }
    let r = resp.json::<BlocksResponse>().await.map_err(|e| e.to_string())?;
    Ok(r.results)
}

pub fn page_title(page: &NotionPage) -> String {
    page.properties
        .get("title")
        .or_else(|| page.properties.get("Name"))
        .and_then(|t| t.get("title"))
        .and_then(|arr| arr.get(0))
        .and_then(|item| item.get("plain_text"))
        .and_then(|v| v.as_str())
        .unwrap_or("Untitled")
        .to_string()
}

pub fn page_status(page: &NotionPage) -> String {
    page.properties
        .get("Status")
        .and_then(|s| s.get("status"))
        .and_then(|s| s.get("name"))
        .and_then(|v| v.as_str())
        .unwrap_or("unknown")
        .to_lowercase()
        .replace(' ', "_")
}

pub fn blocks_to_markdown(blocks: &[NotionBlock]) -> String {
    blocks.iter().map(block_to_line).collect::<Vec<_>>().join("\n")
}

fn block_to_line(block: &NotionBlock) -> String {
    let texts = block.data.get(&block.block_type)
        .and_then(|b| b.get("rich_text"))
        .and_then(|arr| arr.as_array());

    let text = match texts {
        Some(arr) => arr.iter()
            .filter_map(|item| item.get("plain_text").and_then(|v| v.as_str()))
            .collect::<Vec<_>>()
            .join(""),
        None => return String::new(),
    };

    match block.block_type.as_str() {
        "heading_1" => format!("# {text}"),
        "heading_2" => format!("## {text}"),
        "heading_3" => format!("### {text}"),
        "bulleted_list_item" => format!("- {text}"),
        "numbered_list_item" => format!("1. {text}"),
        "code" => format!("```\n{text}\n```"),
        _ => text,
    }
}

use std::path::Path;
use std::time::{SystemTime, UNIX_EPOCH};

pub const DEFAULT_DEST_DIR: &str = "features";
const ROUTING_CONFIG_FILE: &str = ".pks-routing.yaml";

fn extract_dest_dir(line: &str) -> Option<String> {
    let trimmed = line.trim();
    let stripped = trimmed.strip_prefix("tracker_import:")?;
    let val = stripped.trim();
    (!val.is_empty()).then(|| val.to_string())
}

pub fn dest_dir_from_routing(prometheus_root: &Path) -> String {
    let routing_path = prometheus_root.join(ROUTING_CONFIG_FILE);
    let contents = std::fs::read_to_string(&routing_path).unwrap_or_default();
    contents
        .lines()
        .find_map(extract_dest_dir)
        .unwrap_or_else(|| DEFAULT_DEST_DIR.to_string())
}

pub fn file_rel_path_for(tracker_id: &str, dest_dir: &str) -> String {
    let safe_id = tracker_id.replace('/', "-").replace(' ', "_");
    format!("{dest_dir}/{safe_id}.md")
}

pub fn synced_at_now() -> String {
    let secs = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0);
    let (y, mo, d, h, mi, s) = secs_to_parts(secs);
    format!("{y:04}-{mo:02}-{d:02}T{h:02}:{mi:02}:{s:02}Z")
}

fn secs_to_parts(secs: u64) -> (u64, u64, u64, u64, u64, u64) {
    let s = secs % 60;
    let mi = (secs / 60) % 60;
    let h = (secs / 3600) % 24;
    let days = secs / 86400;
    let (y, mo, d) = days_to_ymd(days);
    (y, mo, d, h, mi, s)
}

fn is_leap(year: u64) -> bool {
    year % 4 == 0 && (year % 100 != 0 || year % 400 == 0)
}

fn days_in_year(year: u64) -> u64 {
    match is_leap(year) {
        true => 366,
        false => 365,
    }
}

fn feb_days(year: u64) -> u64 {
    match is_leap(year) {
        true => 29,
        false => 28,
    }
}

fn days_to_ymd(mut days: u64) -> (u64, u64, u64) {
    let mut year = 1970u64;
    loop {
        let diy = days_in_year(year);
        if days < diy { break; }
        days -= diy;
        year += 1;
    }
    let month_days: [u64; 12] = [31, feb_days(year), 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    let mut month = 1u64;
    for md in &month_days {
        if days < *md { break; }
        days -= md;
        month += 1;
    }
    (year, month, days + 1)
}

